<template>
  <div>
    <el-card>
      <div slot="header">订单管理</div>
      <el-form :inline="true" :model="query" size="small" style="margin-bottom:10px">
        <el-form-item label="状态">
          <el-select v-model="query.status" placeholder="全部" clearable>
            <el-option label="待付款" :value="0" /><el-option label="已付款" :value="1" /><el-option label="已取消" :value="2" />
          </el-select>
        </el-form-item>
        <el-form-item><el-button type="primary" @click="loadData">搜索</el-button></el-form-item>
      </el-form>
      <el-table :data="list" border stripe v-loading="loading">
        <el-table-column prop="id" label="ID" width="60" />
        <el-table-column prop="orderNo" label="订单号" width="180" />
        <el-table-column prop="studentName" label="学生" />
        <el-table-column prop="productName" label="商品" />
        <el-table-column prop="quantity" label="数量" width="60" />
        <el-table-column prop="actualAmount" label="总价(元)" width="90" />
        <el-table-column prop="status" label="状态" width="80">
          <template slot-scope="scope">
            <el-tag :type="scope.row.status===1?'success':scope.row.status===2?'info':'warning'" size="small">
              {{ scope.row.status===0?'待付款':scope.row.status===1?'已付款':'已取消' }}
            </el-tag>
          </template>
        </el-table-column>
        <el-table-column prop="createTime" label="下单时间" width="160" />
        <el-table-column label="操作" width="210" align="center">
          <template slot-scope="scope">
            <div class="table-action-btns">
              <el-button v-if="scope.row.status===0" size="mini" type="success" @click="confirmPay(scope.row)">确认付款</el-button>
              <el-button v-if="scope.row.status===0" size="mini" type="danger" @click="cancelOrder(scope.row)">取消</el-button>
            </div>
          </template>
        </el-table-column>
      </el-table>
      <el-pagination style="margin-top:15px;text-align:right" background layout="total, prev, pager, next"
        :total="total" :page-size="query.pageSize" :current-page.sync="query.pageNum" @current-change="loadData" />
    </el-card>
  </div>
</template>
<script>
import request from '@/utils/request'
export default {
  data() {
    return {
      list: [], total: 0, loading: false,
      query: { pageNum: 1, pageSize: 10, status: '' }
    }
  },
  created() { this.loadData() },
  methods: {
    loadData() {
      this.loading = true
      request.get('/api/order', { params: this.query }).then(res => {
        this.list = res.data.records; this.total = res.data.total
      }).finally(() => { this.loading = false })
    },
    confirmPay(row) {
      this.$confirm('确认该订单已付款?', '提示').then(() => {
        request.put('/api/order', { ...row, status: 1 }).then(() => { this.$message.success('操作成功'); this.loadData() })
      }).catch(() => {})
    },
    cancelOrder(row) {
      this.$confirm('确定取消该订单?', '提示', { type: 'warning' }).then(() => {
        request.put('/api/order', { ...row, status: 2 }).then(() => { this.$message.success('已取消'); this.loadData() })
      }).catch(() => {})
    }
  }
}
</script>
